def inject_svgs():
    base_dir = "src/data/seedNotes/physics"
    
    for filename, svgs in svg_data.items():
        filepath = os.path.join(base_dir, filename)
        if not os.path.exists(filepath):
            print(f"File not found: {filepath}")
            continue
            
        with open(filepath, 'r') as f:
            content = f.read()
            
        if "svg-" in content:
            print(f"Skipping {filename} - SVGs already seem to exist")
            continue
            
        # Build SVG block strings
        svg_blocks_str = ""
        for svg_info in svgs:
            block_str = f'''    {{
      "id": "{svg_info['id']}",
      "type": "svg",
      "data": {{
        "svg": "{svg_info['svg']}",
        "caption": "{svg_info['title']}"
      }}
    }},\n'''
            svg_blocks_str += block_str
            
        # Inject right before recall:
        match = re.search(r'(\s+)recall:', content)
        if match:
            indent = match.group(1)
            # Find the closing bracket of the blocks array
            # We look for "],\n  recall:" or something similar.
            replacement = f"{svg_blocks_str}  ],\n  recall:"
            new_content = re.sub(r'\s*],\s*recall:', f"\n{svg_blocks_str}  ],\n  recall:", content)
            
            with open(filepath, 'w') as f:
                f.write(new_content)
            print(f"Injected SVGs into {filename}")
        else:
            print(f"Could not find recall: section in {filename}")

if __name__ == "__main__":
    inject_svgs()
    print("Done generating SVGs.")
